# Shape implementations - classes, enums, inheritance
# Tests: abstract class + interface inheritance across modules

from geometric_base import Point, IGeometry, ITransformable

enum ShapeType:
    CIRCLE = 1
    RECTANGLE = 2
    TRIANGLE = 3

@abstract
class Shape(IGeometry, ITransformable):
    _shape_id: int

    property get id(self) -> int:
        return self._shape_id

    def __init__(self, id: int):
        self._shape_id = id

    @abstract
    def scale(self, factor: float) -> None:
        ...

    @virtual
    def describe(self) -> str:
        return "A geometric shape"

class Rectangle(Shape):
    position: Point
    width: float
    height: float

    def __init__(self, id: int, pos: Point, w: float, h: float):
        super().__init__(id)
        self.position = pos
        self.width = w
        self.height = h

    def get_area(self) -> float:
        return self.width * self.height

    def get_bounds(self) -> tuple[float, float]:
        x_min: float = self.position.x
        x_max: float = x_min + self.width
        y_min: float = self.position.y
        y_max: float = y_min + self.height
        min_val: float = x_min + y_min
        max_val: float = x_max + y_max
        return (min_val, max_val)

    @override
    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

    @override
    def describe(self) -> str:
        return "A rectangle with width " + str(self.width) + " and height " + str(self.height)

class Circle(Shape):
    center: Point
    radius: float

    def __init__(self, id: int, c: Point, r: float):
        super().__init__(id)
        self.center = c
        self.radius = r

    def get_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def get_bounds(self) -> tuple[float, float]:
        min_val: float = self.center.x - self.radius
        max_val: float = self.center.x + self.radius
        return (min_val, max_val)

    @override
    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

    @override
    def describe(self) -> str:
        return "A circle with radius " + str(self.radius)

