# Utility functions for shape operations
# Tests: from-import, higher-order functions, generics across modules

from shapes_impl import Shape, Circle, Rectangle, ShapeType
from geometric_base import IGeometry

def total_area(shapes: list[IGeometry]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.get_area()
    return total

def filter_by_shape_type(shapes: list[Shape], target: ShapeType) -> list[Shape]:
    result: list[Shape] = []
    for s in shapes:
        if isinstance(s, Circle) and target == ShapeType.CIRCLE:
            result.append(s)
        elif isinstance(s, Rectangle) and target == ShapeType.RECTANGLE:
            result.append(s)
    return result

def scale_all(shapes: list[Shape], factor: float) -> None:
    for s in shapes:
        s.scale(factor)

def process_shapes_with_callback(shapes: list[Shape], processor: (Shape) -> str) -> list[str]:
    results: list[str] = []
    for s in shapes:
        results.append(processor(s))
    return results
